import{_ as t,c as a,o,a4 as r}from"./chunks/framework.I1cCAST3.js";const l="/assets/files.MapynkHp.png",u=JSON.parse('{"title":"文件管理","description":"","frontmatter":{},"headers":[],"relativePath":"docs/manage/files/index.md","filePath":"docs/manage/files/index.md"}'),e={name:"docs/manage/files/index.md"},s=r('<h1 id="文件管理" tabindex="-1">文件管理 <a class="header-anchor" href="#文件管理" aria-label="Permalink to &quot;文件管理&quot;">​</a></h1><p>通过 Chaterm 内置的基于 SFTP 的文件管理器，浏览、编辑和传输远程服务器上的文件。</p><p><img src="'+l+'" alt=""></p><h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>在使用文件管理之前，请确保：</p><ul><li>你已与目标主机建立了<strong>活跃的 SSH 连接</strong>。如果尚未连接，请参阅<a href="/docs/hosts/connect">连接主机</a>。</li><li>远程服务器已<strong>启用 SFTP</strong>。大多数 OpenSSH 安装默认启用 SFTP，但某些加固过的服务器可能会禁用它。</li></ul><div class="warning custom-block"><p class="custom-block-title">需要 SFTP</p><p>文件管理完全依赖于服务器的 SFTP 子系统。如果远程服务器未启用 SFTP，浏览、编辑和传输文件将无法工作。如果在文件管理中看到连接错误，请联系服务器管理员启用 SFTP 子系统。</p></div><h2 id="浏览文件" tabindex="-1">浏览文件 <a class="header-anchor" href="#浏览文件" aria-label="Permalink to &quot;浏览文件&quot;">​</a></h2><ol><li>点击左侧菜单栏中的<strong>文件管理</strong>。</li><li>Chaterm 会显示当前已连接主机的远程文件树。</li><li>点击<strong>文件夹</strong>可展开或折叠其内容。</li><li><strong>右键点击</strong>目录，选择<strong>刷新</strong>可重新加载文件列表。</li><li>使用文件树顶部的<strong>搜索栏</strong>按名称查找文件或目录。</li></ol><h2 id="编辑文件" tabindex="-1">编辑文件 <a class="header-anchor" href="#编辑文件" aria-label="Permalink to &quot;编辑文件&quot;">​</a></h2><ol><li><strong>双击</strong>文件树中的文件，在内置编辑器中打开。</li><li>编辑文件内容。编辑器会根据文件类型自动检测并提供语法高亮。</li><li>点击<strong>保存</strong>按钮（或使用快捷键）将更改写回远程服务器。</li></ol><p>编辑器提供现代化的、类 IDE 的体验，支持多语言语法高亮。</p><h2 id="上传文件" tabindex="-1">上传文件 <a class="header-anchor" href="#上传文件" aria-label="Permalink to &quot;上传文件&quot;">​</a></h2><ol><li>在文件树中，导航到你想放置文件的<strong>目标目录</strong>。</li><li>点击<strong>上传</strong>按钮，或直接将一个或多个本地文件拖放到文件树区域。</li><li>选择要上传的文件或文件夹（如果你使用了按钮方式）。</li><li>进度指示器会显示传输速度和百分比。等待上传完成。</li></ol><h2 id="下载文件" tabindex="-1">下载文件 <a class="header-anchor" href="#下载文件" aria-label="Permalink to &quot;下载文件&quot;">​</a></h2><ol><li>在文件树中，找到你想下载的文件或文件夹。</li><li><strong>右键点击</strong>该项目，选择<strong>下载</strong>，或选中该项目后点击<strong>下载</strong>按钮。</li><li>在提示时选择本地保存位置。</li><li>等待下载完成。进度指示器会显示传输状态。</li></ol><h2 id="文件操作" tabindex="-1">文件操作 <a class="header-anchor" href="#文件操作" aria-label="Permalink to &quot;文件操作&quot;">​</a></h2><p>在文件树中右键点击文件或文件夹，可以执行以下操作：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td><strong>重命名</strong></td><td>修改文件或文件夹的名称。</td></tr><tr><td><strong>权限</strong></td><td>修改文件权限（<code>chmod</code>）。在对话框中输入新的权限模式（如 <code>755</code>）。</td></tr><tr><td><strong>复制</strong></td><td>将文件或文件夹复制到服务器上的其他位置。</td></tr><tr><td><strong>移动</strong></td><td>将文件或文件夹移动到服务器上的其他目录。</td></tr><tr><td><strong>删除</strong></td><td>永久删除文件或文件夹。此操作不可逆 —— 请谨慎使用。</td></tr></tbody></table><h2 id="提示" tabindex="-1">提示 <a class="header-anchor" href="#提示" aria-label="Permalink to &quot;提示&quot;">​</a></h2><ul><li><strong>大文件</strong>传输可能需要较长时间。请保持连接，在传输完成前不要离开页面。</li><li><strong>系统文件</strong>可能需要更高的权限。如果无法编辑或删除某个文件，请检查你的用户账户是否具有必要的访问权限。</li><li>在进行编辑之前，特别是在生产服务器上，请<strong>备份重要文件</strong>。</li></ul>',21),i=[s];function n(d,h,c,g,p,_){return o(),a("div",null,i)}const b=t(e,[["render",n]]);export{u as __pageData,b as default};
